-- ============================================================
-- Fix Ancestral Awakening: buff consumption + talent descriptions
-- ============================================================

-- 1. Fix Ancestral Fury buff (200210) consumption.
--    Change from MOD_SPELL_CRIT_CHANCE (global, no auto-consume) to
--    ADD_FLAT_MODIFIER + SPELLMOD_CRITICAL_CHANCE (7) with SpellClassMask
--    targeting shaman damage spells. ProcCharges=1 so the engine auto-
--    consumes the charge when the modifier matches a cast (same pattern
--    as Gift of Nature 200004).
--    SpellClassMaskA = 0x90100003 = LB(1)|CL(2)|ES(0x100000)|FlS(0x10000000)|FrS(0x80000000)
--    SpellClassMaskB = 0x1000 = Lava Burst
UPDATE `alonecraft_spell_dbc` SET
    `EffectApplyAuraName1` = 107,   -- ADD_FLAT_MODIFIER
    `EffectMiscValue1`     = 7,     -- SPELLMOD_CRITICAL_CHANCE
    `EffectSpellClassMaskA1` = -1877999613,  -- unsigned 0x90100003
    `EffectSpellClassMaskB1` = 4096,
    `SpellFamilyName`      = 11,    -- SPELLFAMILY_SHAMAN
    `ProcCharges`          = 1
WHERE `ID` = 200210;

-- 2. Remove spell_proc entry — no longer needed; charges are consumed
--    automatically by the ADD_FLAT_MODIFIER + SpellClassMask mechanism.
DELETE FROM `spell_proc` WHERE `SpellId` = 200210;

